import * as React from "react"

import { cn } from "@/lib/utils"
import { focusRing, surfaceInput, transitionBase } from "@/lib/ui-styles"

function Input({ className, type, ...props }: React.ComponentProps<"input">) {
  return (
    <input
      type={type}
      data-slot="input"
      className={cn(
        "flex h-9 w-full rounded-md border px-3 py-1 text-base shadow-xs file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-muted-foreground disabled:cursor-not-allowed disabled:opacity-50 focus-visible:shadow-none md:text-sm",
        surfaceInput,
        focusRing,
        transitionBase,
        className
      )}
      {...props}
    />
  )
}

export { Input }
